// Explainer integration for inference transparency
function explainInference(model, input, featureNames) {
  const shapValues = model.predictSHAP(input);
  const igValues = model.predictIntegratedGradients(input);
  return {
    prediction: model.predict(input),
    explanations: {
      shap: shapValues,
      integratedGradients: igValues,
      featureNames: featureNames
