// setup autoscaling (simplified)
import { ApplicationAutoScalingClient, RegisterScalableTargetCommand, PutScalingPolicyCommand } from '@aws-sdk/client-application-auto-scaling';
const c = new ApplicationAutoScalingClient({region: 'us-east-1'});
async function cfg(){
  await c.send(new RegisterScalableTarget({
    ServiceNamespace: 'sagemaker',
    ResourceId: 'endpoint/my-image-endpoint/variant/AllTraffic',
    ScalableDimension: 'sagemaker:variant:DesiredInstanceCount',
    MinCapacity: 1,
    MaxCapacity: 20
  }));
  await c.send(new PutScalingPolicy({
    PolicyName: 'LatencyTarget',
    PolicyType: 'TargetTrackingScaling',
    ServiceNamespace: 'sagemaker',
    ResourceId: 'endpoint/my-image-endpoint/variant/AllTraffic',
    ScalableDimension: 'sagemaker:variant:DesiredInstanceCount',
    TargetTrackingScalingPolicyConfiguration: {
      TargetValue: 200
    }
  }));
}
```

